  ('aboriginal-f0899a01-moex-00257', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族語言發展法，下列敘述何者錯誤？', '["原住民人口1,500人以上之非原住民族地區之鄉（鎮、市、區）公所，應置專職原住民族語言推廣 人員", "辦理原住民族語言能力認證應徵收規費", "原住民族地區內之街道，應設置地方通行語及傳統名稱之標示", "學校應依十二年國民基本教育本土語文課程綱要規定，提供原住民族語言課程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00258', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '下列關於原住民族地區資源共同管理辦法之敘述，何者錯誤？', '["中央目的事業主管機關於劃定資源治理區域前，應將計畫目的、範圍、經營管理及與當地共管事項 等計畫內容，於治理區域內鄉（鎮、市）公告閱覽及舉行公聽會，並經當地原住民族同意後，始得 劃定資源治理區域", "中央目的事業主管機關設置資源治理機關後，應遴聘（派）當地原住民族代表、資源治理機關代表 及專家學者，與原住民族建立共同管理機制", "共同管理機制之任務，包含有關資源治理機關涉及當地原住民族之中長程計畫（草案）及年度執行 計畫（草案）之研議", "共同管理機制之組成，由中央目的事業主管機關會同中央原住民族主管機關定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00259', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '有關原住民族土地與諮商事務，依據原住民族基本法第21條規定，下列敘述何者錯誤？', '["本條原住民族土地範圍，係指原住民族既有原住民保留地之意", "須諮商並取得原住民族或部落同意或參與之原住民族土地事項，包括生態保育事務", "按本條原住民得分享相關利益", "原住民族因政府或法令限制其利用土地及自然資源時，其所生之損失應受補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
